"use strict";(self.webpackChunkFaPoems=self.webpackChunkFaPoems||[]).push([[305],{545:(p,e,a)=>{a.r(e),a.d(e,{data:()=>t});const t={key:"v-e1f0c908",path:"/poems/",title:"«گنجور» گنجینه شعر کهن فارسی",lang:"fa-IR",frontmatter:{},excerpt:"",headers:[{level:2,title:"نقطه ای برای شروع",slug:"نقطه-ای-برای-شروع",children:[{level:3,title:"جناب فردوسی",slug:"جناب-فردوسی",children:[]}]}],filePathRelative:"poems/readme.md",git:{updatedTime:1632048941e3,contributors:[{name:"Ali Zemani",email:"mehot1@gmail.com",commits:2}]}}},661:(p,e,a)=>{a.r(e),a.d(e,{default:()=>i});const t=(0,a(252).uE)('<h1 id="«گنجور»-گنجینه-شعر-کهن-فارسی" tabindex="-1"><a class="header-anchor" href="#«گنجور»-گنجینه-شعر-کهن-فارسی" aria-hidden="true">#</a> «گنجور» گنجینه شعر کهن فارسی</h1><p>«گنجور» مجموعه‌ای تحت وب از آثار سخنسرایان پارسی‌گو است که با استفاده از آن می‌توان ضمن مرور به تفکیک نام شاعر و نام آثار او، در بین آثار جستجو کرد.</p><h2 id="نقطه-ای-برای-شروع" tabindex="-1"><a class="header-anchor" href="#نقطه-ای-برای-شروع" aria-hidden="true">#</a> نقطه ای برای شروع</h2><h3 id="جناب-فردوسی" tabindex="-1"><a class="header-anchor" href="#جناب-فردوسی" aria-hidden="true">#</a> جناب فردوسی</h3><div class="fa-poems"><p>به نام خداوند جان و خرد</p><p>کزین برتر اندیشه برنگذرد</p><p>خداوند نام و خداوند جای</p><p>خداوند روزی ده رهنمای</p><p>خداوند کیوان و گردان سپهر</p><p>فروزنده ماه و ناهید و مهر</p><p>ز نام و نشان و گمان برترست</p><p>نگارندهٔ بر شده پیکرست</p><p>به بینندگان آفریننده را</p><p>نبینی مرنجان دو بیننده را</p><p>نیابد بدو نیز اندیشه راه</p><p>که او برتر از نام و از جایگاه</p><p>سخن هر چه زین گوهران بگذرد</p><p>نیابد بدو راه جان و خرد</p><p>خرد گر سخن برگزیند همی</p><p>همان را گزیند که بیند همی</p><p>ستودن نداند کس او را چو هست</p><p>میان بندگی را ببایدت بست</p><p>خرد را و جان را همی سنجد اوی</p><p>در اندیشهٔ سخته کی گنجد اوی</p><p>بدین آلت رای و جان و زبان</p><p>ستود آفریننده را کی توان</p><p>به هستیش باید که خستو شوی</p><p>ز گفتار بی‌کار یکسو شوی</p><p>پرستنده باشی و جوینده راه</p><p>به ژرفی به فرمانش کردن نگاه</p><p>توانا بود هر که دانا بود</p><p>ز دانش دل پیر برنا بود</p><p>از این پرده برتر سخن‌گاه نیست</p><p>ز هستی مر اندیشه را راه نیست</p></div>',5),i={render:function(p,e){return t}}}}]);